namespace sv_8eabae45f2324fb0b2db820e2de28d05.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts per warehouse.
/// Fires <see cref="OnAlertCountChanged"/> whenever new data arrives
/// so all subscribed components update together.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _pollingConsumers;

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>Simulates a database query — returns a random count 0–15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        _ = warehouseId; // would be used in a real DB query
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Begin polling every 10 seconds. Multiple consumers can call this;
    /// polling starts on the first call and stops when the last consumer
    /// calls <see cref="StopPolling"/>.
    /// </summary>
    public void StartPolling(string warehouseId, Func<Func<Task>, Task> invokeAsync)
    {
        _pollingConsumers++;
        if (_pollingConsumers > 1) return; // already polling

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            // Fetch once immediately
            await PollOnce(warehouseId, invokeAsync);

            while (!token.IsCancellationRequested)
            {
                try
                {
                    if (!await _timer.WaitForNextTickAsync(token)) break;
                    await PollOnce(warehouseId, invokeAsync);
                }
                catch (OperationCanceledException) { break; }
            }
        }, token);
    }

    private async Task PollOnce(string warehouseId, Func<Func<Task>, Task> invokeAsync)
    {
        var count = await GetLowStockCountAsync(warehouseId);
        CurrentAlertCount = count;

        // Marshal the event back onto the Blazor sync context
        await invokeAsync(() =>
        {
            OnAlertCountChanged?.Invoke();
            return Task.CompletedTask;
        });
    }

    public void StopPolling()
    {
        _pollingConsumers = Math.Max(0, _pollingConsumers - 1);
        if (_pollingConsumers > 0) return;

        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        _pollingConsumers = 0;
        StopPolling();
    }
}

