@* Interactive island — handles change events for the warehouse dropdown. *@
@inject Services.WarehouseState Warehouse
@implements IDisposable

<div class="warehouse-selector">
    <label for="warehouseSelect" class="form-label text-white mb-1 small">Current Warehouse</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            value="@Warehouse.SelectedWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in Warehouse.Warehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        Warehouse.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
