@page "/dashboard"
@rendermode InteractiveServer
@inject Services.WarehouseState Warehouse
@inject Services.InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="alert alert-info">
    Viewing: <strong>@CurrentWarehouseName</strong>
</div>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card text-white @AlertCardClass">
            <div class="card-body">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4">@AlertService.CurrentAlertCount</p>
                <p class="card-text">Items below minimum level</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card border-primary">
            <div class="card-body">
                <h5 class="card-title">Selected Warehouse</h5>
                <p class="card-text">@CurrentWarehouseName</p>
                <p class="text-muted small">ID: @Warehouse.SelectedWarehouseId</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card border-secondary">
            <div class="card-body">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text text-success">● Active — every 10 s</p>
                <p class="text-muted small">Last check: @_lastCheck.ToString("T")</p>
            </div>
        </div>
    </div>
</div>

@code {
    private Action? _alertHandler;
    private Action? _warehouseHandler;
    private DateTime _lastCheck = DateTime.Now;

    private string CurrentWarehouseName =>
        Warehouse.Warehouses
            .FirstOrDefault(w => w.Id == Warehouse.SelectedWarehouseId)?.Name
        ?? Warehouse.SelectedWarehouseId;

    private string AlertCardClass =>
        AlertService.CurrentAlertCount > 0 ? "bg-danger" : "bg-success";

    protected override void OnInitialized()
    {
        // Subscribe to alert changes (fired from background timer → InvokeAsync)
        _alertHandler = () => InvokeAsync(() =>
        {
            _lastCheck = DateTime.Now;
            StateHasChanged();
        });
        AlertService.OnAlertCountChanged += _alertHandler;

        // Subscribe to warehouse changes so the page updates immediately
        _warehouseHandler = () => InvokeAsync(() =>
        {
            // Restart polling for the new warehouse
            AlertService.StopPolling();
            AlertService.StartPolling(Warehouse.SelectedWarehouseId, InvokeAsync);
            StateHasChanged();
        });
        Warehouse.OnChange += _warehouseHandler;

        // Begin polling for the current warehouse
        AlertService.StartPolling(Warehouse.SelectedWarehouseId, InvokeAsync);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _alertHandler;
        Warehouse.OnChange -= _warehouseHandler;
        AlertService.StopPolling();
    }
}

